INSERT INTO t_p28138419_nova_initiative_14.engineering_articles
(slug, h1, seo_title, seo_description, seo_keywords, summary, quick_facts, body_html, bibliography, author_name, author_role, cover_url, reading_minutes, is_published)
VALUES (
'podbor-podshipnikov-kacheniya-na-resurs-vkr',
'Подбор подшипников качения на ресурс в дипломе: расчёт по динамической грузоподъёмности (ГОСТ 18855-2013)',
'Подбор и расчёт подшипников качения редуктора в ВКР — ресурс L10, динамическая грузоподъёмность · Диплом-Инж.рф',
'Сквозной алгоритм подбора подшипников качения для дипломного проекта: типы подшипников, эквивалентная динамическая нагрузка, расчёт ресурса по базовой динамической грузоподъёмности (ГОСТ 18855-2013), проверка по статической грузоподъёмности, типичные ошибки студентов.',
'подбор подшипников, расчёт подшипника качения, динамическая грузоподъёмность, ресурс подшипника, L10, ГОСТ 18855-2013, эквивалентная нагрузка, подшипник редуктора, опоры вала, радиальный подшипник, роликовый подшипник, ВКР машиностроение, расчёт опор вала',
'Подшипники качения определяют ресурс и надёжность опор вала редуктора. После расчёта вала следующий обязательный раздел дипломного проекта — подбор подшипников и проверка их долговечности. Разбираем алгоритм: от выбора типа до расчёта ресурса по ГОСТ 18855-2013.',
'[
  {"q":"Чем динамическая грузоподъёмность отличается от статической?","a":"Базовая динамическая грузоподъёмность C (Н) — это постоянная радиальная нагрузка, которую подшипник выдержит в течение базового ресурса 1 млн оборотов с вероятностью безотказной работы 90 %. Базовая статическая C_0 (Н) — нагрузка, вызывающая остаточную деформацию 0,0001 диаметра тела качения в наиболее нагруженной точке. C используют для вращающихся опор, C_0 — для неподвижных или медленно вращающихся (n < 10 об/мин) [2, т.2; 6]."},
  {"q":"По какой формуле считают ресурс подшипника?","a":"Базовый расчётный ресурс L_10 = (C / P)^k, млн оборотов, где P — эквивалентная динамическая нагрузка, k = 3 для шариковых и k = 10/3 для роликовых подшипников. Ресурс в часах L_10h = L_10·10⁶ / (60·n), где n — частота вращения, об/мин. Сравнивают с требуемым ресурсом привода [1, с. 211; ГОСТ 18855-2013]."},
  {"q":"Как определяется эквивалентная динамическая нагрузка?","a":"P = (X·V·F_r + Y·F_a)·K_б·K_т, где F_r — радиальная, F_a — осевая нагрузка; X, Y — коэффициенты радиальной и осевой нагрузки (зависят от отношения F_a/(V·F_r) и параметра e); V = 1 при вращении внутреннего кольца; K_б — коэффициент безопасности (1,3…1,5 для редукторов с умеренными толчками); K_т — температурный коэффициент [1, с. 212; 3, с. 117]."},
  {"q":"Какой тип подшипника выбрать для вала редуктора?","a":"Для валов цилиндрических редукторов без осевой нагрузки — шариковые радиальные однорядные (ГОСТ 8338-75): дёшевы, допускают перекос до 0,25°. При значительной осевой нагрузке от косозубых и конических колёс — радиально-упорные шариковые (ГОСТ 831-75) или конические роликовые (ГОСТ 333-79), устанавливаемые по схеме враспор или врастяжку [3, с. 115; 7]."},
  {"q":"Какая надёжность закладывается в расчёт по умолчанию?","a":"Базовый ресурс L_10 соответствует вероятности безотказной работы 90 % (отсюда индекс 10 — допускается 10 % отказов). Для ответственных передач применяют скорректированный ресурс L_na = a_1·a_23·L_10, где a_1 — коэффициент надёжности (a_1 = 0,21 для 99 %), a_23 — коэффициент условий смазки и материала [6; ГОСТ 18855-2013]."}
]'::jsonb,
'<h2>Введение</h2><p>Подшипники качения — опоры, которые воспринимают радиальные и осевые силы от вала и передают их на корпус редуктора. В отличие от валов и зубчатых колёс, подшипники в дипломном проекте не проектируют, а <strong>подбирают</strong> из стандартного ряда и затем <strong>проверяют на ресурс</strong>. Именно эту логику — «подобрал по диаметру, проверил по долговечности» — государственная экзаменационная комиссия и хочет увидеть в разделе расчёта опор.</p><p>В статье — полный алгоритм: выбор типа подшипника по характеру нагрузки, определение реакций опор, расчёт эквивалентной динамической нагрузки, проверка ресурса по базовой динамической грузоподъёмности согласно <strong>ГОСТ 18855-2013</strong> (идентичен ISO 281) и проверка по статической грузоподъёмности. С формулами, ГОСТами и числовыми ориентирами.</p>\n\n<h2>1. Исходные данные</h2><p>Подбор подшипников ведут после расчёта вала и построения эпюр изгибающих моментов. На входе известны: диаметры посадочных шеек вала <em>d</em>, мм (определены при конструировании вала); радиальные реакции опор <em>F<sub>r</sub></em>, Н (из расчёта вала как балки на двух опорах); осевая сила <em>F<sub>a</sub></em>, Н (от косозубой или конической передачи); частота вращения <em>n</em>, об/мин; требуемый ресурс привода <em>L<sub>h треб</sub></em>, часов (обычно 10 000…20 000 ч для редукторов общего назначения).</p>\n\n<h2>2. Выбор типа подшипника</h2><p>Тип подшипника определяется соотношением осевой и радиальной нагрузок и требованиями к жёсткости опоры:</p><ul><li><strong>Шариковые радиальные однорядные (ГОСТ 8338-75)</strong> — основной выбор для валов прямозубых цилиндрических редукторов. Воспринимают радиальную и небольшую осевую нагрузку, допускают перекос колец до 0,25°, дёшевы и технологичны.</li><li><strong>Радиально-упорные шариковые (ГОСТ 831-75)</strong> — при значительной осевой нагрузке от косозубых колёс. Устанавливают парами по схеме «враспор» или «врастяжку».</li><li><strong>Конические роликовые (ГОСТ 333-79)</strong> — для тяжелонагруженных валов с большой осевой силой (червячные, конические передачи). Высокая грузоподъёмность, но требуют регулировки осевого зазора.</li><li><strong>Роликовые радиальные с короткими цилиндрическими роликами (ГОСТ 8328-75)</strong> — при больших радиальных нагрузках и недопустимости осевой фиксации (плавающая опора).</li></ul>\n\n<h2>3. Реакции опор</h2><p>Вал рассматривают как балку на двух шарнирных опорах. Радиальные реакции <em>F<sub>r</sub></em> в вертикальной и горизонтальной плоскостях находят из уравнений равновесия, затем суммируют геометрически: F<sub>r</sub> = √(R<sub>в</sub>² + R<sub>г</sub>²). Осевую силу F<sub>a</sub> воспринимает та опора, которая зафиксирована в осевом направлении (фиксирующая опора), либо распределяют между опорами для радиально-упорных подшипников с учётом осевых составляющих S = e·F<sub>r</sub> [1, с. 215; 3, с. 118].</p>\n\n<h2>4. Эквивалентная динамическая нагрузка</h2><p>Реальная комбинированная нагрузка приводится к условной радиальной — эквивалентной динамической нагрузке:</p><p style="text-align:center"><strong>P = (X·V·F<sub>r</sub> + Y·F<sub>a</sub>)·K<sub>б</sub>·K<sub>т</sub></strong></p><p>где X — коэффициент радиальной нагрузки, Y — коэффициент осевой нагрузки. Их выбирают по отношению F<sub>a</sub>/(V·F<sub>r</sub>) относительно параметра осевого нагружения <em>e</em>: если F<sub>a</sub>/(V·F<sub>r</sub>) ≤ e, то X = 1, Y = 0 (осевую нагрузку не учитывают); если больше — X = 0,56, Y берут из таблиц по каталогу. V = 1 при вращении внутреннего кольца; K<sub>б</sub> = 1,3…1,5 — коэффициент безопасности для редукторов с умеренными толчками; K<sub>т</sub> = 1 при рабочей температуре до 100 °C [1, с. 212; 3, с. 117].</p>\n\n<h2>5. Расчёт ресурса по динамической грузоподъёмности</h2><p>Базовый расчётный ресурс подшипника:</p><p style="text-align:center"><strong>L<sub>10</sub> = (C / P)<sup>k</sup>, млн оборотов</strong></p><p>где C — базовая динамическая грузоподъёмность из каталога подшипника, Н; k = 3 для шариковых, k = 10/3 для роликовых подшипников. Ресурс в часах:</p><p style="text-align:center"><strong>L<sub>10h</sub> = L<sub>10</sub>·10<sup>6</sup> / (60·n)</strong></p><p>Условие пригодности: L<sub>10h</sub> ≥ L<sub>h треб</sub>. Если ресурс недостаточен — переходят на подшипник большей серии (средней, тяжёлой) того же внутреннего диаметра либо на роликовый тип [1, с. 211; ГОСТ 18855-2013].</p>\n\n<h2>6. Скорректированный ресурс</h2><p>Для ответственных передач рассчитывают скорректированный ресурс с учётом надёжности и условий эксплуатации:</p><p style="text-align:center"><strong>L<sub>na</sub> = a<sub>1</sub>·a<sub>23</sub>·L<sub>10</sub></strong></p><p>где a<sub>1</sub> — коэффициент надёжности (a<sub>1</sub> = 1 для 90 %, 0,62 для 95 %, 0,21 для 99 %); a<sub>23</sub> — обобщённый коэффициент качества материала и условий смазки (0,7…1,4) [6; ГОСТ 18855-2013].</p>\n\n<h2>7. Проверка по статической грузоподъёмности</h2><p>Для тихоходных (n < 10 об/мин) и неподвижных опор основным является расчёт по статической грузоподъёмности: P<sub>0</sub> = X<sub>0</sub>·F<sub>r</sub> + Y<sub>0</sub>·F<sub>a</sub> ≤ C<sub>0</sub>, где C<sub>0</sub> — базовая статическая грузоподъёмность из каталога. Проверка исключает остаточную деформацию (бринеллирование) дорожек качения при пиковых нагрузках и в покое [2, т. 2; 6].</p>\n\n<h2>8. Типичные ошибки в дипломах</h2><ul><li>Не учитывают осевую силу от косозубой передачи и считают подшипник только по радиальной нагрузке — ресурс завышается в разы.</li><li>Путают коэффициент k для шариковых (3) и роликовых (10/3) подшипников.</li><li>Берут грузоподъёмность C для лёгкой серии, когда габарит позволяет среднюю, и получают недостаточный ресурс.</li><li>Не проверяют тихоходную опору по статической грузоподъёмности C<sub>0</sub>.</li><li>Игнорируют коэффициент безопасности K<sub>б</sub>, занижая фактическую нагрузку.</li></ul>\n\n<h2>Заключение</h2><p>Подбор подшипников — это не «вытащил из методички», а связная цепочка: тип под характер нагрузки → реакции опор → эквивалентная нагрузка → ресурс по ГОСТ 18855-2013 → проверка по статике. Грамотно подобранная опора обеспечивает заявленный ресурс редуктора при минимальной массе и стоимости. Именно умение довести этот расчёт до числа и сопоставить с требуемым ресурсом отличает инженера, проектирующего надёжные отечественные машины, от формального исполнителя дипломного раздела.</p>',
'[
